import {
  type KeyboardEvent as ReactKeyboardEvent,
  useCallback,
  useEffect,
  useRef,
  useState,
} from 'react';
import { useIntl } from 'react-intl';

import Spacings from '@dynatrace/strato-design-tokens/spacings';
import { DotMenuIcon, DownloadIcon } from '@dynatrace/strato-icons';

import { AsyncIntents } from './AsyncIntents.js';
import { triggerButton } from './ChartDataMenu.sty.js';
import {
  styledToolbarMenuContainer,
  toolbarMenuGroup,
} from './ToolbarMenu.sty.js';
import { Button } from '../../../../../buttons/button/Button.js';
import type { IntentProps } from '../../../../../core/slots/Intent/Intent.js';
import { Menu } from '../../../../../navigation/menu/Menu.js';
import { useA11yToolbarTabIndex } from '../../../hooks/useA11yToolbarTabIndex.js';
import { useEffectOnValueChange } from '../../../hooks/useEffectOnValueChange.js';
import { TOOLBAR_MESSAGES } from '../messages.js';
import type { IntentsAsyncTemplate } from '../types.js';
import { VerticalDivider } from './divider.js';

interface ChartDataMenuProps {
  onMenuEnter: () => void;
  onMenuLeave: () => void;
  onMenuOpen: (open: boolean) => void;
  handleDownloadDataToolbar?: () => void;
  menuAlignment?: 'center' | 'end' | 'start';
  isDownloadEnabled?: boolean;
  intents?: Array<IntentProps>;
  showDivider: boolean;
  isDragging?: boolean;
  buttonMode: 'standard' | 'inline';
  intentsAsyncTemplate?: IntentsAsyncTemplate;
}

export const ChartDataMenu = ({
  onMenuEnter,
  onMenuLeave,
  onMenuOpen,
  menuAlignment = 'end',
  isDownloadEnabled,
  handleDownloadDataToolbar,
  intents = [],
  showDivider,
  buttonMode = 'standard',
  isDragging,
  intentsAsyncTemplate,
}: ChartDataMenuProps) => {
  const intentButtonRef = useRef<HTMLButtonElement>(null);
  const menuContentRef = useRef<HTMLDivElement>(null);
  const tabIndex = useA11yToolbarTabIndex('intent');
  const intl = useIntl();
  const [isOpen, setIsOpen] = useState(false);
  const isInlineMode = buttonMode === 'inline';

  const handleOnMouseEnter = () => {
    onMenuEnter?.();
  };

  useEffectOnValueChange(() => {
    onMenuOpen(isOpen);
  }, [isOpen]);

  useEffect(() => {
    if (tabIndex === 0 && intentButtonRef.current) {
      intentButtonRef.current?.focus();
    }
  }, [intentButtonRef, tabIndex]);

  useEffect(() => {
    if (isDragging !== undefined && isDragging && isOpen) {
      setIsOpen(false);
    }
  }, [isDragging, isOpen]);

  const handleOnMouseLeave = () => {
    onMenuLeave?.();
  };

  const handleToolbarMenuClick = () => {
    setIsOpen((prevState) => !prevState);
  };

  const handleOnClickOutsideOverlay = useCallback(
    (e: MouseEvent) => {
      const menuContainsTarget = menuContentRef.current?.contains(
        e.target as Node,
      );

      if (isOpen && !menuContainsTarget) {
        setIsOpen(false);
      }
    },
    [setIsOpen, isOpen, menuContentRef],
  );

  // We have to use the keyup event, because the keydown event propagation is stopped inside the Menu component.
  const handleOnKeyUp = useCallback(
    (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        setIsOpen(false);
      }
    },
    [setIsOpen],
  );

  const handleOnKeyDown = (e: ReactKeyboardEvent) => {
    const nativeEvent = e.nativeEvent;

    if (nativeEvent.code === 'Enter') {
      setIsOpen((prevState) => !prevState);
    }
  };

  useEffect(() => {
    window.addEventListener('click', handleOnClickOutsideOverlay);
    window.addEventListener('keyup', handleOnKeyUp);

    return () => {
      window.removeEventListener('click', handleOnClickOutsideOverlay);
      window.removeEventListener('keyup', handleOnKeyUp);
    };
  }, [handleOnClickOutsideOverlay, handleOnKeyUp]);

  return (
    <div
      className={styledToolbarMenuContainer({
        inline: isInlineMode,
      })}
      onMouseEnter={handleOnMouseEnter}
      onMouseLeave={handleOnMouseLeave}
      onClick={handleToolbarMenuClick}
      onKeyDown={handleOnKeyDown}
      ref={menuContentRef}
    >
      {showDivider && <VerticalDivider />}

      <Menu open={isOpen}>
        <Menu.Trigger>
          <Button
            width={Spacings.Size28}
            className={isInlineMode ? triggerButton : undefined}
            variant="default"
            size="condensed"
            ref={intentButtonRef}
            tabIndex={tabIndex}
          >
            <DotMenuIcon />
          </Button>
        </Menu.Trigger>
        <Menu.Content alignment={menuAlignment}>
          <Menu.Group className={toolbarMenuGroup}>
            {isDownloadEnabled && handleDownloadDataToolbar ? (
              <Menu.Item onSelect={handleDownloadDataToolbar}>
                <Menu.Prefix>
                  <DownloadIcon />
                </Menu.Prefix>
                {intl.formatMessage(TOOLBAR_MESSAGES.downloadDataButton)}
              </Menu.Item>
            ) : null}
          </Menu.Group>
          {intents.length ? (
            <Menu.Group className={toolbarMenuGroup}>
              {intents.map((item, key) => (
                <Menu.Intent {...item} key={item.children?.toString() || key}>
                  {item.icon && <Menu.Prefix>{item.icon}</Menu.Prefix>}
                  {item.children}
                </Menu.Intent>
              ))}
            </Menu.Group>
          ) : null}
          <AsyncIntents
            intentsAsyncTemplate={intentsAsyncTemplate}
            shouldRun={isOpen}
          />
        </Menu.Content>
      </Menu>
    </div>
  );
};
